import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicThreeDays() {
        // [100,200,300]: accept days 0 and 2 → 100+300 = 400
        assertEquals(400L, new Solution().maxRevenue(new int[]{100, 200, 300}));
    }

    @Test
    void singleDay() {
        assertEquals(500L, new Solution().maxRevenue(new int[]{500}));
    }

    @Test
    void emptySchedule() {
        assertEquals(0L, new Solution().maxRevenue(new int[]{}));
    }

    @Test
    void symmetricEnds() {
        // [400,100,100,400]: accept days 0 and 3 → 800
        assertEquals(800L, new Solution().maxRevenue(new int[]{400, 100, 100, 400}));
    }

    @Test
    void allSameHighValue() {
        // [10000,10000,10000,10000,10000]: alternating → 3 × 10000 = 30000
        assertEquals(30000L, new Solution().maxRevenue(new int[]{10000, 10000, 10000, 10000, 10000}));
    }

    @Test
    void twoDays() {
        // [300, 500]: can only pick one — pick the larger
        assertEquals(500L, new Solution().maxRevenue(new int[]{300, 500}));
    }

    @Test
    void longReturnTypeSafety() {
        // 100 days of 10000 each: alternating picks 50 days → 500000L (fits in int but asserted as long)
        int[] schedule = new int[100];
        java.util.Arrays.fill(schedule, 10000);
        assertEquals(500000L, new Solution().maxRevenue(schedule));
    }
}
